      if (aiProvider === "Gemini") { response = await fetch(`${providerDefaults.Gemini.baseUrl}/models/${encodeURIComponent(aiModel)}:generateContent`, { method: "POST", headers: { "Content-Type": "application/json", "x-goog-api-key": apiKey }, body: JSON.stringify({ contents: [{ parts: [{ text: instruction }] }], generationConfig: { responseMimeType: "application/json" } }) }); const data = await response.json(); if (!response.ok) throw new Error(data.error?.message || "Gemini 请求失败"); text = data.candidates?.[0]?.content?.parts?.[0]?.text || ""; }
      else if (aiProvider === "Claude") { response = await fetch(`${providerDefaults.Claude.baseUrl}/messages`, { method: "POST", headers: { "Content-Type": "application/json", "x-api-key": apiKey, "anthropic-version": "2023-06-01" }, body: JSON.stringify({ model: aiModel, max_tokens: 300, messages: [{ role: "user", content: instruction }] }) }); const data = await response.json(); if (!response.ok) throw new Error(data.error?.message || "Claude 请求失败"); text = data.content?.[0]?.text || ""; }
      else { const baseUrl = aiProvider === "Custom" ? customProvider.baseUrl.replace(/\/$/, "") : providerDefaults[aiProvider]?.baseUrl; if (!baseUrl || !baseUrl.startsWith("https://")) throw new Error("请填写有效的 HTTPS API Base URL"); response = await fetch(`${baseUrl}/chat/completions`, { method: "POST", headers: { "Content-Type": "application/json", Authorization: `Bearer ${apiKey}` }, body: JSON.stringify({ model: aiProvider === "Custom" ? customProvider.model || aiModel : aiModel, messages: [{ role: "user", content: instruction }], temperature: 0 }) }); const data = await response.json(); if (!response.ok) throw new Error(data.error?.message || "AI 请求失败"); text = data.choices?.[0]?.message?.content || ""; }
      const parsed = JSON.parse(text.replace(/^```json\s*|\s*```$/g, "").trim());
      const requested: unknown[] = Array.isArray(parsed.resourceIds) ? parsed.resourceIds : Array.isArray(parsed.resources) ? parsed.resources : [];
